#!/usr/bin/env python3
"""make-tokenizer-gguf.py — emit a tokenizer-only GGUF for the mesh.

Produces a small GGUF carrying ONLY `tokenizer.ggml.*` metadata (no tensors)
that the consolidated mesh's qwen2-family GGUF tokenizer path reads:
  open-source/gnosis/distributed-inference-host/src/qwen-tokenizer.ts
    loadQwenTokenizerFromGguf → readTokenizerMetadata

That reader REQUIRES (throws otherwise):
  - tokenizer.ggml.tokens   (string array, the vocab; index == token id)
  - tokenizer.ggml.merges   (string array, "<left> <right>" BPE merge rules)
and OPTIONALLY reads:
  - tokenizer.ggml.bos_token_id / eos_token_id / padding_token_id (uint32)

This is the clean equivalent of the loki recipe (`head -c 30M full.gguf`),
but built directly from a HuggingFace byte-level-BPE tokenizer.json so we
don't need a multi-GB source GGUF. Both gpt-neox-20b (mamba) and falcon
(falcon-mamba) are GPT-2-style byte-level BPE with an explicit merges list,
which is exactly what the qwen-tokenizer.ts BPE encoder expects.

Usage:
  python3 make-tokenizer-gguf.py --hf-model EleutherAI/gpt-neox-20b \
      --out /tmp/mamba-2.8b-tokenizer.gguf --arch mamba
  python3 make-tokenizer-gguf.py --hf-model tiiuae/falcon-mamba-7b \
      --out /tmp/falcon-mamba-7b-tokenizer.gguf --arch falcon-mamba
"""
from __future__ import annotations

import argparse
import json
import sys
from pathlib import Path

from gguf import GGUFWriter


def load_tokenizer_json(hf_model: str) -> dict:
    """Fetch tokenizer.json from a HF repo (downloads only the small file)."""
    from huggingface_hub import hf_hub_download

    path = hf_hub_download(repo_id=hf_model, filename="tokenizer.json")
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def extract_vocab_and_merges(tok: dict) -> tuple[list[str], list[str], dict]:
    model = tok.get("model") or {}
    if model.get("type") != "BPE":
        # gpt-neox-20b / falcon are both BPE; bail loudly if not.
        print(
            f"[warn] tokenizer model type is {model.get('type')!r}, expected BPE",
            file=sys.stderr,
        )

    vocab = model.get("vocab")
    if not vocab:
        raise SystemExit("tokenizer.json has no model.vocab")

    # vocab is { token: id }. Build the id-indexed token list.
    max_id = max(vocab.values())
    tokens: list[str] = [""] * (max_id + 1)
    for token, tid in vocab.items():
        tokens[tid] = token

    # added_tokens (specials like <|endoftext|>, <|padding|>) override / fill.
    added = tok.get("added_tokens") or []
    for at in added:
        tid = at.get("id")
        content = at.get("content")
        if tid is None or content is None:
            continue
        if tid >= len(tokens):
            tokens.extend([""] * (tid - len(tokens) + 1))
        tokens[tid] = content

    # Any remaining empty slots → byte-fallback placeholder so the array is dense
    # and index == id holds. (Real vocabs are dense; this is defensive.)
    holes = [i for i, t in enumerate(tokens) if t == ""]
    if holes:
        print(f"[warn] {len(holes)} empty vocab slots, filling placeholders", file=sys.stderr)
        for i in holes:
            tokens[i] = f"<|unused{i}|>"

    merges_raw = model.get("merges") or []
    merges: list[str] = []
    for m in merges_raw:
        if isinstance(m, list):
            merges.append(f"{m[0]} {m[1]}")
        else:
            merges.append(m)

    if not merges:
        raise SystemExit("tokenizer.json has no model.merges (loader requires merges)")

    return tokens, merges, tok


def resolve_special_id(tok: dict, tokens: list[str], names: list[str]) -> int | None:
    """Find a special-token id by trying each candidate content string."""
    # Build content→id from added_tokens first (authoritative for specials).
    by_content: dict[str, int] = {}
    for at in tok.get("added_tokens") or []:
        if at.get("content") is not None and at.get("id") is not None:
            by_content[at["content"]] = at["id"]
    vocab = (tok.get("model") or {}).get("vocab") or {}
    for name in names:
        if name in by_content:
            return by_content[name]
        if name in vocab:
            return vocab[name]
    return None


def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument("--hf-model", required=True)
    ap.add_argument("--out", required=True)
    ap.add_argument("--arch", default="tokenizer-only")
    args = ap.parse_args()

    print(f"[fetch] tokenizer.json from {args.hf_model}")
    tok = load_tokenizer_json(args.hf_model)
    tokens, merges, tok = extract_vocab_and_merges(tok)
    print(f"[vocab] {len(tokens)} tokens, {len(merges)} merges")

    bos = resolve_special_id(tok, tokens, ["<|endoftext|>", "<s>", "<|begin_of_text|>"])
    eos = resolve_special_id(tok, tokens, ["<|endoftext|>", "</s>", "<|eot_id|>"])
    pad = resolve_special_id(tok, tokens, ["<|padding|>", "<|endoftext|>", "<pad>"])
    print(f"[special] bos={bos} eos={eos} pad={pad}")

    out = Path(args.out)
    writer = GGUFWriter(str(out), arch=args.arch)
    writer.add_name(f"{args.arch}-tokenizer")
    # Minimal but well-formed: a generic ggml tokenizer model marker + arrays.
    writer.add_tokenizer_model("gpt2")
    writer.add_token_list(tokens)
    writer.add_token_merges(merges)
    if bos is not None:
        writer.add_bos_token_id(bos)
    if eos is not None:
        writer.add_eos_token_id(eos)
    if pad is not None:
        writer.add_pad_token_id(pad)

    writer.write_header_to_file()
    writer.write_kv_data_to_file()
    # No tensors → no tensor data section. The file is metadata-only.
    writer.close()

    size_mb = out.stat().st_size / 1024 / 1024
    print(f"[done] wrote {out} ({size_mb:.1f} MB)")


if __name__ == "__main__":
    main()
